package main

import (
	"time"
	"encoding/hex"

	"gno.land/p/aib/ibc/lightclient/tendermint"
	"gno.land/p/aib/ibc/types"
	"gno.land/p/aib/ics23"
	"gno.land/r/aib/ibc/core"
)
func hexDec(s string) []byte {
  b, err := hex.DecodeString(s)
                 if err != nil { panic(err) }
  return b
}
func main(cur realm) {
	// CreateClient
	var (
		chainID      = "atomone-testnet-1"
		latestHeight = types.Height{ 
			RevisionNumber: 1,
			RevisionHeight: 8171097,
		}
		clientState = tendermint.ClientState{
			ChainID:         chainID,
			TrustLevel:      tendermint.Fraction{2, 3},
			UnbondingPeriod: time.Second * 1814400,
			TrustingPeriod:  time.Second * 1209600,
			MaxClockDrift:   time.Second * 20,
			LatestHeight:    latestHeight,
			ProofSpecs:      ics23.GetSDKProofSpecs(),
		}
		apphash        = hexDec("988bb068e1fa5b23c71131a848a13994de1404c5389a359d3abb10f95a22f0f2")
		valhash        = hexDec("1613669b802a2ee4bf88c1cb57fde08d96cda4a16f6ae9edf3e917fc4342f912")
		timestamp      = time.Unix(1784895981, 807541435)
		consensusState = tendermint.ConsensusState{
			Timestamp:          timestamp,
			Root:               tendermint.MerkleRoot{Hash: apphash[:]},
			NextValidatorsHash: valhash[:],
		}
	)
	id := core.CreateClient(cross(cur), clientState, consensusState)
	println(id)
}

package main

